from google.cloud import pubsub_v1, taskqueue

def process_message(event, context):
    for message in event['data']:
        pubsub_message = message.data
        data = pickle.loads(pubsub_message)
        # Process the deserialized Python object here

        task = taskqueue.Task(
            project=context.project,
            queue_name='your-taskqueue',
            http_method=taskqueue.HttpMethod.POST,
            url='/some-endpoint?data={}'.format(json.dumps(data)),
            retries=3
        )
        taskqueue.Client().create(task)

def on_publish(event, context):
    pubsub_message = event['data']
    pubsub_client = pubsub_v1.PublisherClient()
    topic_path = pubsub_client.topic_path('your-project', 'your-topic')
    future = pubsub_client.publish(topic_path, data=pickle.dumps(event['data']))
    future.result()